import{c as r,Q as t,j as o,m as s}from"./chunks/framework.BPKcPtvA.js";const u=JSON.parse('{"title":"How do I remove a user from my customer?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/recipes/portal/remove-user.md","filePath":"guide/recipes/portal/remove-user.md","lastUpdated":1779094756000}'),a={name:"guide/recipes/portal/remove-user.md"};function i(n,e,l,m,d,c){return t(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="how-do-i-remove-a-user-from-my-customer" tabindex="-1">How do I remove a user from my customer? <a class="header-anchor" href="#how-do-i-remove-a-user-from-my-customer" aria-label="Permalink to &quot;How do I remove a user from my customer?&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Who can do this</p><p><strong>Owner</strong> or <strong>Admin</strong></p></div><p>Removing a user revokes their access to the customer <strong>and every tenant</strong> they were on. This is irreversible — bringing them back means re-inviting and re-assigning them from scratch.</p><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><ol><li>Open <strong>Users</strong> in the sidebar.</li><li>Click the row of the user you want to remove.</li><li>Click <strong>Remove from Customer</strong> in the actions menu.</li><li>Confirm — the dialog lists every tenant they&#39;ll be removed from.</li></ol><div class="warning custom-block"><p class="custom-block-title">You can&#39;t remove the Owner</p><p>Transfer ownership first (see <a href="./transfer-ownership">transfer ownership</a>), then remove.</p></div><h2 id="result" tabindex="-1">Result <a class="header-anchor" href="#result" aria-label="Permalink to &quot;Result&quot;">​</a></h2><p>The user disappears from the Users table and from every tenant they were assigned to. Their authentication identity (in Zitadel) is <em>not</em> deleted — if they belong to another customer, they keep access there.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./suspend-user">How do I suspend or reactivate a user?</a></li><li><a href="./transfer-ownership">How do I transfer ownership of my customer?</a></li></ul>',10)])])}const p=r(a,[["render",i]]);export{u as __pageData,p as default};
